50	  }
51	
52	  /**
53	   * Factory screen production orders — same pagination contract as getProdOrderHeader (startRow, endRow, filterModel).
54	   * Rows include prodReferenceNo for dropdown labels; scoped by factoryId + vendor (same rules as before).
55	   */
56	  getFactoryProdOrderList(
57	    factoryId: number | null,
58	    pagination?: { startRow?: number; endRow?: number; filterModel?: Record<string, unknown> }
59	  ) {
60	    const startRow = pagination?.startRow ?? 0;
61	    const endRow = pagination?.endRow ?? startRow + 10000;
62	    const filterModel = pagination?.filterModel ?? {};
63	
64	    let params = new HttpParams()
65	      .set('startRow', String(startRow))
66	      .set('endRow', String(endRow))
67	      .set('filterModel', JSON.stringify(filterModel));
68	
69	    if (factoryId !== undefined && factoryId !== null) {
70	      params = params.set('factoryId', String(factoryId));
71	    }
72	
73	    return this.http.get(`${this.serverAddress}/factoryProdOrders`, {
74	      headers: this.setUserAuthWithLoader(),
75	      params
76	    });
