import { Injectable } from '@angular/core'
import { Observable, pipe } from 'rxjs'
import { HttpClient, HttpParams } from '@angular/common/http'
import { map, catchError } from 'rxjs/operators';
import { HttpHeaders } from '@angular/common/http';
import { environment } from '../../../environments/environment';
@Injectable({
  providedIn: 'root',
})
export class TrackingService {
  serverAddress = environment.tracking;
  constructor(private http: HttpClient) {
  }
  setUserAuth() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders()
      .set('Authorization', token)
    return headers
  }

  setUserAuthWithLoader() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders()
      .set('Authorization', token)
      .set('X-Enable-Loader', 'true')
    return headers
  }

  getProdOrderHeader(pagination: { startRow?: number, endRow?: number, filterModel?: string}) {
    // Set defaults in the service method
    const startRow = pagination.startRow ?? 0
    const endRow = pagination.endRow ?? 100
    const filterModel = pagination.filterModel

    const params = new HttpParams()
      .set('startRow', startRow.toString())
      .set('endRow', endRow.toString())
      .set('filterModel', JSON.stringify(filterModel))

    return this.http.get(`${this.serverAddress}/getProdOrderHeader`, {
      headers: this.setUserAuthWithLoader(),
      params
    });
  }
  getViewlayout(grid_id) {
    return this.http.get(`${this.serverAddress}/getViewlayout/${grid_id}`, { headers: this.setUserAuth() })
  }
  updateProdOrderHeader(data) {
    return this.http.post(this.serverAddress + '/updateProdOrderHeader', data, { headers: this.setUserAuth() })
  }

  /**
   * Factory screen production orders — same pagination contract as getProdOrderHeader (startRow, endRow, filterModel).
   * Rows include prodReferenceNo for dropdown labels; scoped by factoryId + vendor (same rules as before).
   */
  getFactoryProdOrderList(
    factoryId: number | null,
    pagination?: { startRow?: number; endRow?: number; filterModel?: Record<string, unknown> }
  ) {
    const startRow = pagination?.startRow ?? 0;
    const endRow = pagination?.endRow ?? startRow + 10000;
    const filterModel = pagination?.filterModel ?? {};

    let params = new HttpParams()
      .set('startRow', String(startRow))
      .set('endRow', String(endRow))
      .set('filterModel', JSON.stringify(filterModel));

    if (factoryId !== undefined && factoryId !== null) {
      params = params.set('factoryId', String(factoryId));
    }

    return this.http.get(`${this.serverAddress}/factoryProdOrders`, {
      headers: this.setUserAuthWithLoader(),
      params
    });
  }

  updateFactoryProdOrderDates(body: {
    id: number;
    material_arrival_date: string | null;
    mass_prod_start_date: string | null;
    assembly_start_date: string | null;
    actual_prod_complete: string | null;
    packing_start_date: string | null;
    qc_inspection_date: string | null;
    actual_etd: string | null;
  }) {
    return this.http.post(`${this.serverAddress}/factoryProdOrderDates`, body, { headers: this.setUserAuth() });
  }

  getProdTrackingDetails() {
    return this.http.get(this.serverAddress + '/getProdTrackingDetails', { headers: this.setUserAuth() })
  }

  // ----------------------------- Sample tracking -----------------------------
  // Server-side grid contract: ?startRow&endRow&filterModel -> { rows, totalCount }
  getSamples(pagination: { startRow?: number; endRow?: number; filterModel?: any }) {
    const startRow = pagination.startRow ?? 0
    const endRow = pagination.endRow ?? 100
    const params = new HttpParams()
      .set('startRow', String(startRow))
      .set('endRow', String(endRow))
      .set('filterModel', JSON.stringify(pagination.filterModel ?? {}))
    return this.http.get(`${this.serverAddress}/sample/list`, { headers: this.setUserAuthWithLoader(), params })
  }

  getSample(id: number) {
    return this.http.get(`${this.serverAddress}/sample/${id}`, { headers: this.setUserAuth() })
  }

  createSample(body: any) {
    return this.http.post(`${this.serverAddress}/sample`, body, { headers: this.setUserAuth() })
  }

  updateSample(id: number, body: any) {
    return this.http.put(`${this.serverAddress}/sample/${id}`, body, { headers: this.setUserAuth() })
  }

  deleteSample(id: number) {
    return this.http.delete(`${this.serverAddress}/sample/${id}`, { headers: this.setUserAuth() })
  }

  // Bidirectional check-in/out engine. body: { sample_id_fk, event_type, office_location, notes?, to_status? }
  recordSampleEvent(body: any) {
    return this.http.post(`${this.serverAddress}/sample/events`, body, { headers: this.setUserAuth() })
  }

  getSampleEvents(id: number) {
    return this.http.get(`${this.serverAddress}/sample/${id}/events`, { headers: this.setUserAuth() })
  }

  // Comments
  getSampleComments(id: number) {
    return this.http.get(`${this.serverAddress}/sample/${id}/comments`, { headers: this.setUserAuth() })
  }
  addSampleComment(body: any) {
    return this.http.post(`${this.serverAddress}/sample/comments`, body, { headers: this.setUserAuth() })
  }
  updateSampleComment(id: number, body: any) {
    return this.http.put(`${this.serverAddress}/sample/comments/${id}`, body, { headers: this.setUserAuth() })
  }
  deleteSampleComment(id: number) {
    return this.http.delete(`${this.serverAddress}/sample/comments/${id}`, { headers: this.setUserAuth() })
  }

  // Photos (presigned upload flow)
  getSamplePhotos(id: number) {
    return this.http.get(`${this.serverAddress}/sample/${id}/photos`, { headers: this.setUserAuth() })
  }
  getSamplePreSignedUrl(body: { fileName: string; contentType: string }) {
    return this.http.post(`${this.serverAddress}/sample/getPreSignedUrl`, body, { headers: this.setUserAuth() })
  }
  setSampleObjectPublic(body: { fileName: string }) {
    return this.http.post(`${this.serverAddress}/sample/setObjectPublic`, body, { headers: this.setUserAuth() })
  }
  addSamplePhoto(body: any) {
    return this.http.post(`${this.serverAddress}/sample/photos`, body, { headers: this.setUserAuth() })
  }
  deleteSamplePhoto(attId: number) {
    return this.http.delete(`${this.serverAddress}/sample/photos/${attId}`, { headers: this.setUserAuth() })
  }

  // Factory groups
  getSampleGroups() {
    return this.http.get(`${this.serverAddress}/sample/groups`, { headers: this.setUserAuth() })
  }
  createSampleGroup(body: any) {
    return this.http.post(`${this.serverAddress}/sample/groups`, body, { headers: this.setUserAuth() })
  }
  updateSampleGroup(id: number, body: any) {
    return this.http.put(`${this.serverAddress}/sample/groups/${id}`, body, { headers: this.setUserAuth() })
  }
  deleteSampleGroup(id: number) {
    return this.http.delete(`${this.serverAddress}/sample/groups/${id}`, { headers: this.setUserAuth() })
  }

  // Boxes (Ningbo <-> NYC). Status is independent of member samples.
  getSampleBoxes() {
    return this.http.get(`${this.serverAddress}/sample/boxes`, { headers: this.setUserAuth() })
  }
  createSampleBox(body: any) {
    return this.http.post(`${this.serverAddress}/sample/boxes`, body, { headers: this.setUserAuth() })
  }
  updateSampleBox(id: number, body: any) {
    return this.http.put(`${this.serverAddress}/sample/boxes/${id}`, body, { headers: this.setUserAuth() })
  }
  deleteSampleBox(id: number) {
    return this.http.delete(`${this.serverAddress}/sample/boxes/${id}`, { headers: this.setUserAuth() })
  }
  addSamplesToBox(boxId: number, body: {
    sample_ids: number[];
    leg_type?: string;
    next_stop?: string | null;
    final_destination?: string | null;
  }) {
    return this.http.post(`${this.serverAddress}/sample/boxes/${boxId}/items`, body, { headers: this.setUserAuth() })
  }
  removeSamplesFromBox(boxId: number, body: { sample_ids: number[] }) {
    return this.http.request('delete', `${this.serverAddress}/sample/boxes/${boxId}/items`, { body, headers: this.setUserAuth() })
  }

}

