// --- Samples (Backend PR-1 frozen contract) ---
router.get('/list', authRole(READ), SampleController.list);
router.get('/:id/events', authRole(READ), SampleController.listEvents);

// --- Comments (PR-2). Registered before '/:id' so the static segments win. ---
router.get('/:id/comments', authRole(READ), SampleCommentController.list);
router.post('/comments', authRole(READ), SampleCommentController.add);
router.put('/comments/:id', authRole(READ), SampleCommentController.update);
router.delete('/comments/:id', authRole(READ), SampleCommentController.remove);

