const Sample = require('../models/sample.model.js');

// Map a model-layer error onto an HTTP response. Model methods signal failures
// either as a real Error or as a plain { status, message } object (e.g. a 409
// concurrency conflict or a 400 illegal transition).
function sendErr(res, err, fallback) {
  const httpStatus = Number(err && err.status) || 500;
  res.status(httpStatus).send({
    message: (err && err.message) || fallback || 'Unexpected error'
  });
}

exports.list = (req, res) => {
  Sample.list(req, (err, data) => {
    if (err) sendErr(res, err, 'Error retrieving samples.');
    else res.send(data);
  });
};

exports.getById = (req, res) => {
  Sample.getById(req, (err, data) => {
    if (err) sendErr(res, err, 'Error retrieving sample.');
    else res.send(data);
  });
};

exports.create = (req, res) => {
  if (!req.body || Object.keys(req.body).length === 0) {
    return res.status(400).send({ message: 'Content can not be empty!' });
  }
  Sample.create(req, (err, data) => {
    if (err) sendErr(res, err, 'Error creating sample.');
    else res.send(data);
  });
};

exports.createCustomer = (req, res) => {
  req.sampleOrigin = 'customer';
  req.body = req.body || {};
  Sample.create(req, (err, data) => {
    if (err) sendErr(res, err, 'Error creating customer sample.');
    else res.send(data);
  });
};

exports.update = (req, res) => {
  if (!req.body) {
    return res.status(400).send({ message: 'Content can not be empty!' });
  }
  Sample.update(req, (err, data) => {
    if (err) sendErr(res, err, 'Error updating sample.');
    else res.send(data);
  });
};

exports.remove = (req, res) => {
  Sample.remove(req, (err, data) => {
    if (err) sendErr(res, err, 'Error deleting sample.');
    else res.send(data);
  });
};

exports.recordEvent = (req, res) => {
  if (!req.body) {
    return res.status(400).send({ message: 'Content can not be empty!' });
  }
  Sample.recordEvent(req, (err, data) => {
    if (err) sendErr(res, err, 'Error recording sample event.');
    else res.send(data);
  });
};

exports.listEvents = (req, res) => {
  Sample.listEvents(req, (err, data) => {
    if (err) sendErr(res, err, 'Error retrieving sample events.');
    else res.send(data);
  });
};

