var DataTypes = require("sequelize").DataTypes;
const fs = require('fs');
const path = require('path');

function initModels(sequelize) {
  var primaryTables = []
  var jointTables = []
  const files = {};
  var filenames = []

  //define modules
  // object to hold all the models to export
  // Read all the files from this dir and load the models

  fs.readdirSync(__dirname)
    .forEach((file) => {
      if (file !== path.basename(__filename) && file.endsWith('.js')) {
        var filename = file.replace(/\.js$/, '')
        filenames.push(filename)
        var model = require(path.join(__dirname, '/', filename));
        files[filename] = model;
      }
    });

  var models = {}
  for (var i = 0; filenames.length > i; i++) {
    var modelName = files[filenames[i]](sequelize, DataTypes)
    models[filenames[i]] = modelName
  }

  // Explicit associations that may not be described in UDFTable
  if (models.itemHeader && models.itemAttachment && models.itemHeader.hasMany) {
    try {
      models.itemHeader.hasMany(models.itemAttachment, { as: 'itemAttachments', foreignKey: 'item_num_id_fk', sourceKey: 'item_id_pk' })
    } catch (e) {
      console.log('Skipping manual association itemHeader -> itemAttachment', e?.message)
    }
  }

  if (models.itemHeader && models.licensingStatus && models.itemHeader.hasMany) {
    try {
      models.itemHeader.hasMany(models.licensingStatus, { as: 'licensingStatuses', foreignKey: 'itemheader_id_fk', sourceKey: 'item_id_pk' })
    } catch (e) {
      console.log('Skipping manual association itemHeader -> licensingStatus', e?.message)
    }
  }

  if (models.itemHeader && models.licensingMilestone) {
    try {
      models.itemHeader.hasMany(models.licensingMilestone, {
        as: 'licensingMilestones',
        foreignKey: 'itemheader_id_fk',
        sourceKey: 'item_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association itemHeader -> licensingMilestone', e?.message);
    }
  }

  // Image history association
  if (models.itemHeader && models.itemLicenseImage && models.itemHeader.hasMany) {
    try {
      models.itemHeader.hasMany(models.itemLicenseImage, { as: 'licenseImages', foreignKey: 'itemheader_id_fk', sourceKey: 'item_id_pk' })
    } catch (e) {
      console.log('Skipping manual association itemHeader -> itemLicenseImage', e?.message)
    }
  }

  // Comments association
  if (models.itemHeader && models.comments && models.itemHeader.hasMany) {
    try {
      models.itemHeader.hasMany(models.comments, { as: 'comments', foreignKey: 'item_header_id', sourceKey: 'item_id_pk' })
    } catch (e) {
      console.log('Skipping manual association itemHeader -> comments', e?.message)
    }
  }

  // Groups -> LicensingStatus association
  if (models.groups && models.licensingStatus && models.groups.hasMany) {
    try {
      models.groups.hasMany(models.licensingStatus, { as: 'licensingStatuses', foreignKey: 'tagged_group_id' });
      models.licensingStatus.belongsTo(models.groups, { as: 'taggedGroup', foreignKey: 'tagged_group_id' });
    } catch (e) {
      console.log('Skipping manual association groups -> licensingStatus', e?.message)
    }
  }

  // Define associations for all 10 merchGroup relationships
  for (let i = 1; i <= 10; i++) {
    const groupNum = String(i).padStart(2, '0');

    // Determine the correct foreign key column name
    const foreignKey = i <= 4 ?
      `udf_merchgroup${groupNum}_id` :  // Groups 01-04 use _id
      `udf_merchgroup${groupNum}_fk_id`; // Groups 05-10 use _fk_id

    models.itemHeader.belongsTo(models.merchGroup, {
      as: `merchGroup${groupNum}`,
      foreignKey: foreignKey,
      targetKey: 'mg_id'
    });
  }

  // GridAccessLevel -> GridLayout association for layout includes
  if (models.GridAccessLevel && models.GridLayout && models.GridAccessLevel.hasMany) {
    try {
      models.GridAccessLevel.hasMany(models.GridLayout, {
        as: 'GridLayouts',
        foreignKey: 'col_id',
        sourceKey: 'col_id'
      })
    } catch (e) {
      console.log('Skipping manual association GridAccessLevel -> GridLayout', e?.message)
    }
  }

  // ProdOrderHeader -> ProdOrderDetail association on prodOrderNo
  if (models.ProdOrderHeader && models.ProdOrderDetail && models.ProdOrderHeader.hasMany) {
    try {
      models.ProdOrderHeader.hasMany(models.ProdOrderDetail, { as: 'ProdOrderDetails', foreignKey: 'prodOrderNo' });
      models.ProdOrderDetail.belongsTo(models.ProdOrderHeader, { as: 'ProdOrderHeader', foreignKey: 'prodOrderNo' });
    } catch (e) {
      console.log('Skipping manual association ProdOrderHeader -> ProdOrderDetail', e?.message)
    }
  }

  // ProdOrderDetail -> itemHeader direct association for simple (non-prepack) items
  // where ProdOrderDetail.itemNo = itemHeader.item_num_id
  if (models.ProdOrderDetail && models.itemHeader) {
    try {
      models.ProdOrderDetail.hasOne(models.itemHeader, {
        as: 'directItemHeader',
        foreignKey: 'item_num_id',
        sourceKey: 'itemNo',
        constraints: false
      });
    } catch (e) {
      console.log('Skipping ProdOrderDetail -> itemHeader direct association', e?.message);
    }
  }

  // itemHeader <-> ProdOrderDetail many-to-many associations through item number matching
  if (models.itemHeader && models.ProdOrderDetail && models.item_prod_order_detail_associations) {
    try {
      models.itemHeader.hasMany(models.item_prod_order_detail_associations, {
        as: 'itemProdOrderDetailAssociations',
        foreignKey: 'itemHeaderId',
        sourceKey: 'item_id_pk'
      });
      models.ProdOrderDetail.hasMany(models.item_prod_order_detail_associations, {
        as: 'itemProdOrderDetailAssociations',
        foreignKey: 'prodOrderDetailPkey',
        sourceKey: 'pkey'
      });
      models.item_prod_order_detail_associations.belongsTo(models.itemHeader, {
        as: 'itemHeader',
        foreignKey: 'itemHeaderId',
        targetKey: 'item_id_pk'
      });
      models.item_prod_order_detail_associations.belongsTo(models.ProdOrderDetail, {
        as: 'prodOrderDetail',
        foreignKey: 'prodOrderDetailPkey',
        targetKey: 'pkey'
      });
      models.itemHeader.belongsToMany(models.ProdOrderDetail, {
        as: 'linkedProdOrderDetails',
        through: models.item_prod_order_detail_associations,
        foreignKey: 'itemHeaderId',
        otherKey: 'prodOrderDetailPkey'
      });
      models.ProdOrderDetail.belongsToMany(models.itemHeader, {
        as: 'linkedItemHeaders',
        through: models.item_prod_order_detail_associations,
        foreignKey: 'prodOrderDetailPkey',
        otherKey: 'itemHeaderId'
      });
    } catch (e) {
      console.log('Skipping manual association itemHeader <-> ProdOrderDetail', e?.message)
    }
  }

  // Sample tracking: sample -> sample_event history
  if (models.sample && models.sample_event && models.sample.hasMany) {
    try {
      models.sample.hasMany(models.sample_event, {
        as: 'events',
        foreignKey: 'sample_id_fk',
        sourceKey: 'sample_id_pk'
      });
      models.sample_event.belongsTo(models.sample, {
        as: 'sample',
        foreignKey: 'sample_id_fk',
        targetKey: 'sample_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association sample -> sample_event', e?.message);
    }
  }

  // Sample tracking: sample -> sample_comments, and comment author
  if (models.sample && models.sample_comments && models.sample.hasMany) {
    try {
      models.sample.hasMany(models.sample_comments, {
        as: 'sampleComments',
        foreignKey: 'sample_id_fk',
        sourceKey: 'sample_id_pk'
      });
      if (models.users) {
        models.sample_comments.belongsTo(models.users, {
          as: 'users',
          foreignKey: 'user_id'
        });
      }
    } catch (e) {
      console.log('Skipping manual association sample -> sample_comments', e?.message);
    }
  }

  // Sample tracking: sample -> sample_attachment (photos)
  if (models.sample && models.sample_attachment && models.sample.hasMany) {
    try {
      models.sample.hasMany(models.sample_attachment, {
        as: 'sampleAttachments',
        foreignKey: 'sample_id_fk',
        sourceKey: 'sample_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association sample -> sample_attachment', e?.message);
    }
  }

  // Sample tracking: factory group -> samples
  if (models.sample_factory_group && models.sample && models.sample_factory_group.hasMany) {
    try {
      models.sample_factory_group.hasMany(models.sample, {
        as: 'samples',
        foreignKey: 'factory_group_id_fk',
        sourceKey: 'factory_group_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association sample_factory_group -> sample', e?.message);
    }
  }

  // Sample tracking: box -> samples (current-box cache) and box<->sample via shipment items
  if (models.sample_box && models.sample && models.sample_box.hasMany) {
    try {
      models.sample_box.hasMany(models.sample, {
        as: 'boxSamples',
        foreignKey: 'box_id_fk',
        sourceKey: 'box_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association sample_box -> sample', e?.message);
    }
  }
  if (models.sample && models.sample_shipment_item && models.sample.hasMany) {
    try {
      models.sample.hasMany(models.sample_shipment_item, {
        as: 'shipmentItems',
        foreignKey: 'sample_id_fk',
        sourceKey: 'sample_id_pk'
      });
      models.sample_box.hasMany(models.sample_shipment_item, {
        as: 'shipmentItems',
        foreignKey: 'box_id_fk',
        sourceKey: 'box_id_pk'
      });
    } catch (e) {
      console.log('Skipping manual association sample_shipment_item', e?.message);
    }
  }

  models.UDFTable.findAll({
    where: {
      container_id: 'tracking'
    }
  })
    .then(data => {
      if (data) {
        //if UDFElement_id_fk is 0 it means that we will run that on constructor
        //if UDFTable_primary_id is 0 and UDFTable_associate_type is 0 then that is the primary table for the associations
        data.forEach(element => {
          if (element.UDFTable_primary_id == '0') {
            primaryTables.push(element)
          } else {
            jointTables.push(element)
          }
        });
        //define modules associations
        for (var i = 0; jointTables.length > i; i++) {
          primaryTables.forEach(pkTablesElement => {
            if (jointTables[i].UDFTable_foreignKey != '0' && jointTables[i].UDFTable_targetKey != '0' && parseInt(pkTablesElement.UDFTable_id) === parseInt(jointTables[i].UDFTable_primary_id)) {
              models[pkTablesElement.UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey, sourceKey: jointTables[i].UDFTable_targetKey })
            } else if (jointTables[i].UDFTable_foreignKey != '0' && parseInt(pkTablesElement.UDFTable_id) === parseInt(jointTables[i].UDFTable_primary_id)) {
              models[pkTablesElement.UDFTable_name][jointTables[i].UDFTable_associate_type](models[jointTables[i].UDFTable_name], { foreignKey: jointTables[i].UDFTable_foreignKey })
            }
          });
        };
      } else {
      }
    })
  return models
}
module.exports = initModels;
module.exports.initModels = initModels;
module.exports.default = initModels;

