var DBConfig = require('../config/db.config')()
var Sequelize = require('sequelize');
var db = {};

initialize();
async function initialize() {
    // connect to db
    let sq_config = {
        dialect: 'postgres',
        host: DBConfig.HOST,
        schema: process.env.SCHEMA,
        logging: false,
        pool: {
            max: 22,
            min: 1,
            acquire: 600000,
            idle: 100000,
        },
        createdAt: false,
        updatedAt: false,
        timestamp: false,
        dialectOptions: {
            connectTimeout: 3000000,
        }
    };

    const sequelize = new Sequelize(DBConfig.DB, DBConfig.DBUser, DBConfig.PASSWORD, sq_config);

    // Populate the exported `db` object SYNCHRONOUSLY (before any await). Model
    // definitions don't need an authenticated connection, and index.js calls
    // startServer() -> db.LicenseFeedBacks.findAll() synchronously right after
    // require('./models/db') returns. Mutate (Object.assign) rather than
    // reassign so the `module.exports = db` reference stays valid. Awaiting
    // before this line would leave consumers holding an empty object.
    Object.assign(db, require('./db/init-models')(sequelize))
    db.sequelize = sequelize

    try {
        await sequelize.authenticate();
    } catch (error) {
        console.error('Unable to connect to the database:', error);
        throw 'Unable to connect to the database:', error
    }

    // Models are the schema source of truth: sync() creates brand-new tables
    // (e.g. the sample-tracking tables) without altering existing ones.
    await sequelize.sync();

    // Idempotent, awaited migration block for FUTURE column additions. Runs
    // AFTER sync() so it never races. Use snake_case identifiers only (mixed
    // case folds to lowercase in unquoted Postgres DDL and orphans the column).
    await applySampleMigrations(sequelize);
}

/**
 * Additive, idempotent DDL for the sample-tracking module. Every statement is
 * IF NOT EXISTS and individually guarded so a re-deploy never crashes boot.
 */
async function applySampleMigrations(sequelize) {
    const schema = process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
    const statements = [
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS sample_name VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS quantity INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS retail_price DECIMAL(12, 2)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS fob_cost DECIMAL(12, 2)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS customer_id_fk INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS courier VARCHAR(20)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS tracking_number VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS factory_id_fk INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS factory_group_id_fk INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS box_id_fk INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS office_location VARCHAR(20)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS next_stop VARCHAR(50)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS final_destination VARCHAR(50)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS notes TEXT`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS item_id_fk INTEGER`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS prod_order_no_fk VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_createdTime" VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_createdUser" VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_modTime" VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample" ADD COLUMN IF NOT EXISTS "sample_modUser" VARCHAR(255)`,
        `ALTER TABLE ${schema}"sample_box" ADD COLUMN IF NOT EXISTS final_destination VARCHAR(50)`,
        `ALTER TABLE ${schema}"sample_event" ADD COLUMN IF NOT EXISTS notes TEXT`
    ];
    for (const stmt of statements) {
        try {
            await sequelize.query(stmt);
        } catch (err) {
            console.warn('Sample migration skipped:', err?.message);
        }
    }
}
module.exports = db;

