const ProdTracking = function (ProdTracking) {
  this.Data = ProdTracking.Data;
};

function decodeAuthUser(req) {
  const token = req.headers.authorization;
  if (!token) {
    throw new Error('Missing authorization token');
  }
  return jwt.verify(token, jwtPublicKey, jwtVerifyOptions);
}

function qualifyTableName(tableName) {
