jest.mock('../../models/db', () => ({
  sample: {
    findAndCountAll: jest.fn(),
    findByPk: jest.fn(),
    create: jest.fn(),
    update: jest.fn(),
    destroy: jest.fn()
  },
  sample_event: {
    create: jest.fn(),
    findAll: jest.fn(),
    destroy: jest.fn()
  }
}));

jest.mock('../../helpers/auth', () => ({
  getUserInfo: jest.fn(async () => ({ user_id: 7, name: 'Alice', role: 'admin' }))
}));

const sql = require('../../models/db');
const { getUserInfo } = require('../../helpers/auth');
const Sample = require('../../models/sample.model');

// Invoke a callback-style model method and resolve with { err, data }.
function run(method, req) {
  return new Promise((resolve) => {
    method(req, (err, data) => resolve({ err, data }));
  });
}

const auth = { headers: { authorization: 'token' } };

describe('Sample.create', () => {
  it('defaults direction/status from origin and writes an initial event', async () => {
    sql.sample.create.mockResolvedValue({ sample_id_pk: 10 });
    sql.sample_event.create.mockResolvedValue({});

    const { err, data } = await run(Sample.create, { ...auth, body: { origin: 'factory_request', sample_name: 'Widget' } });

    expect(err).toBeFalsy();
    expect(data).toEqual({ sample_id_pk: 10 });

    const created = sql.sample.create.mock.calls[0][0];
    expect(created.direction).toBe('inbound');
    expect(created.status).toBe('requested');
    expect(created.sample_createdUser).toBe('Alice');

    const event = sql.sample_event.create.mock.calls[0][0];
    expect(event).toMatchObject({ sample_id_fk: 10, from_status: null, to_status: 'requested' });
  });

  it('persists integration link columns (item_id_fk / prod_order_no_fk)', async () => {
    sql.sample.create.mockResolvedValue({ sample_id_pk: 12 });
    sql.sample_event.create.mockResolvedValue({});

    await run(Sample.create, { ...auth, body: { origin: 'factory_request', item_id_fk: 555, prod_order_no_fk: 'PO-900' } });

    const created = sql.sample.create.mock.calls[0][0];
    expect(created.item_id_fk).toBe(555);

