/* TEMP diagnostic — connects to the real DB, measures /sample/list cost. Deleted after use. */
const { Client } = require('pg');
const schema = process.env.SCHEMA;
const q = (name) => `"${schema}"."${name}"`;

(async () => {
  const client = new Client({
    host: process.env.DB_HOST,
    port: Number(process.env.DB_PORT) || 5432,
    user: process.env.DB_USER,
    password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME,
    ssl: { rejectUnauthorized: false },
    connectionTimeoutMillis: 20000,
    statement_timeout: 60000,
  });

  const t0 = Date.now();
  await client.connect();
  console.log(`connect: ${Date.now() - t0}ms`);

  const time = async (label, sql) => {
    const s = Date.now();
    try {
      const r = await client.query(sql);
      console.log(`${label}: ${Date.now() - s}ms  rows=${r.rowCount}`);
      return r;
    } catch (e) {
      console.log(`${label}: ERROR after ${Date.now() - s}ms -> ${e.message}`);
      return null;
    }
  };

  await time('count sample', `SELECT count(*) FROM ${q('sample')}`);
  await time('count sample_attachment', `SELECT count(*) FROM ${q('sample_attachment')}`);
  await time('count sample_box', `SELECT count(*) FROM ${q('sample_box')}`);

  // The two queries findAndCountAll({distinct:true, include sampleAttachments}) generates:
  await time('list COUNT (distinct join)',
    `SELECT count(DISTINCT "sample"."sample_id_pk") AS cnt
     FROM ${q('sample')} AS "sample"
     LEFT OUTER JOIN ${q('sample_attachment')} AS "sa" ON "sample"."sample_id_pk" = "sa"."sample_id_fk"`);

  await time('list SELECT page (limit 100, join)',
    `SELECT "sample".*, "sa".*
     FROM ${q('sample')} AS "sample"
     LEFT OUTER JOIN ${q('sample_attachment')} AS "sa" ON "sample"."sample_id_pk" = "sa"."sample_id_fk"
     WHERE "sample"."sample_id_pk" IN (
       SELECT "sample_id_pk" FROM ${q('sample')} ORDER BY "sample_id_pk" DESC LIMIT 100
     )
     ORDER BY "sample"."sample_id_pk" DESC`);

  // Indexes on the join column?
  const idx = await client.query(
    `SELECT tablename, indexname, indexdef FROM pg_indexes
     WHERE schemaname = $1 AND tablename IN ('sample','sample_attachment','sample_box')
     ORDER BY tablename, indexname`, [schema]);
  console.log('\nindexes:');
  idx.rows.forEach(r => console.log(`  ${r.tablename}.${r.indexname}: ${r.indexdef}`));

  // Any blocking locks / long-running queries right now?
  const locks = await client.query(
    `SELECT pid, state, wait_event_type, wait_event, now()-query_start AS dur, left(query,80) AS q
     FROM pg_stat_activity
     WHERE datname = current_database() AND state <> 'idle' AND pid <> pg_backend_pid()
     ORDER BY dur DESC NULLS LAST LIMIT 10`);
  console.log('\nactive sessions:');
  locks.rows.forEach(r => console.log(`  pid=${r.pid} state=${r.state} wait=${r.wait_event_type}/${r.wait_event} dur=${r.dur} q=${r.q}`));

  await client.end();
})().catch(e => { console.error('FATAL', e.message); process.exit(1); });

