// The grid page is a plain paginated scan of `sample`. We deliberately do NOT
// join `sample_attachment` here: a `findAndCountAll({distinct:true, include:
// hasMany})` makes Postgres LEFT JOIN every attachment, de-duplicate, and run
// COUNT(DISTINCT ...) — which made /sample/list take 10-30s once any sample had
// photos (it blew past the BFF 30s timeout → "Failed to load samples"). Without
// the include the count is a trivial COUNT(*) and the page uses the PK index for
// ORDER BY sample_id_pk DESC LIMIT. Photos and box labels are added below via
// separate, batched, index-backed lookups (the same shape as the box query).
const { count, rows } = await sql.sample.findAndCountAll({
  where: whereClause,
  order: [['sample_id_pk', 'DESC']],
  limit,
  offset
});

const mapped = rows.map(r => (r && typeof r.get === 'function') ? r.get({ plain: true }) : r);

// Surface a primary_photo thumbnail URL on each row for the grid (batched).
const sampleIds = mapped.map(r => r.sample_id_pk).filter(v => v != null);
if (sampleIds.length && sql.sample_attachment) {
  const atts = await sql.sample_attachment.findAll({
    where: { sample_id_fk: { [Op.in]: sampleIds } },
    attributes: ['sample_id_fk', 'attachment_link', 'primary_image']
  });
  // Pick one photo per sample: prefer the one flagged primary_image, else any.
  const photoBySample = new Map();
  atts.forEach(a => {
    const p = (a && typeof a.get === 'function') ? a.get({ plain: true }) : a;
    const cur = photoBySample.get(p.sample_id_fk);
    if (!cur || (p.primary_image && !cur.primary_image)) photoBySample.set(p.sample_id_fk, p);
  });
  mapped.forEach(r => {
    const p = photoBySample.get(r.sample_id_pk);
    r.primary_photo = p ? p.attachment_link : null;
  });
} else {
  mapped.forEach(r => { r.primary_photo = null; });
}

// Surface the box label (so the grid shows which box a sample is in).
const boxIds = [...new Set(mapped.map(r => r.box_id_fk).filter(Boolean))];
if (boxIds.length && sql.sample_box) {
  const boxes = await sql.sample_box.findAll({ where: { box_id_pk: { [Op.in]: boxIds } } });
  const labels = new Map(boxes.map(b => [b.box_id_pk, b.box_label]));

