const fs = require('fs');
const path = require('path');

const read = (rel) => fs.readFileSync(path.join(__dirname, '..', '..', rel), 'utf8');

describe('sample model schema', () => {
  const sampleSrc = read('models/db/sample.js');
  const eventSrc = read('models/db/sample_event.js');

  it('defines the sample table with its key columns', () => {
    expect(sampleSrc).toMatch(/tableName:\s*'sample'/);
    ['sample_id_pk', 'origin', 'direction', 'quantity', 'retail_price', 'fob_cost',
      'customer_id_fk', 'courier', 'tracking_number',
      'factory_id_fk', 'factory_group_id_fk', 'box_id_fk', 'status', 'office_location', 'notes',
      'item_id_fk', 'prod_order_no_fk']
      .forEach(col => expect(sampleSrc).toContain(col));
  });

  it('defines the sample_event table with its key columns', () => {
    expect(eventSrc).toMatch(/tableName:\s*'sample_event'/);
    ['event_id_pk', 'sample_id_fk', 'event_type', 'from_status', 'to_status',
      'office_location', 'event_user', 'event_time']
      .forEach(col => expect(eventSrc).toContain(col));
  });
});

describe('db.js migration block', () => {
  const dbSrc = read('models/db.js');

  it('awaits sync() so brand-new tables are created deterministically', () => {
    expect(dbSrc).toMatch(/await\s+sequelize\.sync\(\)/);
  });

  it('runs an awaited, idempotent ADD COLUMN IF NOT EXISTS block after sync', () => {
    expect(dbSrc).toContain('applySampleMigrations');
    expect(dbSrc).toMatch(/ADD COLUMN IF NOT EXISTS/);
  });

  it('keeps deployed sample tables aligned with fields written on create', () => {
    ['sample_name', 'quantity', 'retail_price', 'fob_cost', 'factory_id_fk',
      'customer_id_fk', 'courier', 'tracking_number',
      'factory_group_id_fk', 'box_id_fk', 'office_location', 'next_stop',
      'final_destination', 'notes', 'item_id_fk', 'prod_order_no_fk',
      '"sample_createdTime"', '"sample_createdUser"', '"sample_modTime"', '"sample_modUser"']
      .forEach(col => expect(dbSrc).toContain(`ADD COLUMN IF NOT EXISTS ${col}`));
  });

  it('preserves the exported db reference via Object.assign (no reassignment)', () => {
    expect(dbSrc).toMatch(/Object\.assign\(db,/);
  });

  it('populates db synchronously BEFORE awaiting authenticate (startServer reads db at boot)', () => {
    // index.js calls startServer() -> db.LicenseFeedBacks.findAll() synchronously
    // right after require(). If we await before Object.assign, db is still empty.
    const assignIdx = dbSrc.indexOf('Object.assign(db,');
    const authIdx = dbSrc.indexOf('await sequelize.authenticate()');
    expect(assignIdx).toBeGreaterThan(-1);
    expect(authIdx).toBeGreaterThan(-1);
    expect(assignIdx).toBeLessThan(authIdx);
  });

  it('never adds a mixed-case column in raw DDL (SYS-002)', () => {
    const addColumnLines = dbSrc.split('\n').filter(l => /ADD COLUMN IF NOT EXISTS/.test(l));
    addColumnLines.forEach(line => {
      const m = line.match(/ADD COLUMN IF NOT EXISTS\s+([A-Za-z0-9_"]+)/);
      const ident = (m && m[1] || '').replace(/"/g, '');
      // unquoted identifiers must be all lower-case snake to avoid folding
      if (!line.includes(`"${ident}"`)) {
        expect(ident).toBe(ident.toLowerCase());
      }
    });
  });
});

describe('db.js connection pool resilience (SAMPLE-LIST timeout fix)', () => {
  const dbSrc = read('models/db.js');

  // The tracking service reaches a pooled/managed Postgres (Supabase) over TCP.
  // The pooler drops idle client connections, so a long-lived idle Sequelize
  // connection becomes a half-open dead socket. Reusing it stalled the next
  // query for 10-25s before the OS reported the socket dead — pushing the rarely
  // hit /sample/list past the BFF's 30s proxy timeout ("Failed to load samples").
  // These assertions lock in the settings that prevent that regression.
  const BFF_PROXY_TIMEOUT_MS = 30000;

  const numAfter = (key) => {
    const m = dbSrc.match(new RegExp(`${key}\\s*:\\s*(\\d+)`));
    return m ? Number(m[1]) : null;
  };

  it('enables TCP keep-alive so dead sockets are detected, not stalled on', () => {
    expect(dbSrc).toMatch(/keepAlive\s*:\s*true/);
    expect(numAfter('keepAliveInitialDelayMillis')).toBeGreaterThan(0);
  });

  it('does not hold idle connections that can go stale behind the pooler (min: 0)', () => {
    expect(numAfter('min')).toBe(0);
  });

  it('evicts idle connections quickly, before the pooler closes them', () => {
    const idle = numAfter('idle');
    expect(idle).toBeGreaterThan(0);
    expect(idle).toBeLessThanOrEqual(30000);
    // an eviction sweep must actually run for `idle` to take effect
    expect(numAfter('evict')).toBeGreaterThan(0);
  });

  it('fails fast on connection acquire instead of hanging past the BFF timeout', () => {
    const acquire = numAfter('acquire');
    expect(acquire).toBeGreaterThan(0);
    expect(acquire).toBeLessThan(BFF_PROXY_TIMEOUT_MS);
  });

  it('caps the TCP connect time below the BFF proxy timeout', () => {
    const connectTimeout = numAfter('connectTimeout');
    expect(connectTimeout).toBeGreaterThan(0);
    expect(connectTimeout).toBeLessThan(BFF_PROXY_TIMEOUT_MS);
  });
});

describe('init-models associations + status enum', () => {
  it('wires the sample -> sample_event association', () => {
    const initSrc = read('models/db/init-models.js');
    expect(initSrc).toMatch(/models\.sample\.hasMany\(models\.sample_event/);
  });

  it('exposes the full status list from the state machine', () => {
    const statusMod = require('../../helpers/sampleStatus');
    ['requested', 'shipped', 'ningbo_checked_in', 'ningbo_checked_out', 'nyc_checked_in',
      'nyc_requested', 'nyc_checked_out', 'sent_to_factory',
      'cancelled', 'on_hold', 'damaged', 'approved']
      .forEach(s => expect(statusMod.ALL_STATUSES).toContain(s));
  });
});

