import { Component, Inject } from '@angular/core';
import { FormControl } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Observable } from 'rxjs';
import { map, startWith } from 'rxjs/operators';
import { ORIGINS, ORIGIN_DEFAULTS, OFFICES, SAMPLE_STOPS, statusLabel, directionLabel } from '../helpers/sample.status';

interface CustomerOption {
  customers_id: number;
  customers_name: string;
}

// Create a new sample. Origin drives direction + initial status (server confirms).
@Component({
  selector: 'sample-create-dialog',
  standalone: false,
  templateUrl: './create-dialog.component.html',
  styleUrls: ['./create-dialog.component.scss']
})
export class CreateDialogComponent {
  origins = ORIGINS;
  offices = OFFICES;
  stops = SAMPLE_STOPS;
  couriers = [
    { value: 'ups', label: 'UPS' },
    { value: 'fedex', label: 'FedEx' },
    { value: 'aae', label: 'AAE' },
    { value: 'bombino', label: 'Bombino' }
  ];
  customers: CustomerOption[] = [];
  customerControl = new FormControl<CustomerOption | string | null>(null);
  filteredCustomers$: Observable<CustomerOption[]>;

  model: any = {
    origin: 'factory_request',
    sample_name: '',
    quantity: null,
    retail_price: null,
    fob_cost: null,
    customer_id_fk: null,
    courier: null,
    tracking_number: '',
    factory_id_fk: null,
    office_location: null,
    next_stop: null,
    final_destination: null,
    notes: ''
  };

  constructor(
    public dialogRef: MatDialogRef<CreateDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: { customers?: CustomerOption[] } | null
  ) {
    this.customers = (data && data.customers ? data.customers : [])
      .filter((c: any) => c && c.customers_id != null)
      .map((c: any) => ({ customers_id: Number(c.customers_id), customers_name: c.customers_name || `Customer #${c.customers_id}` }));
    this.filteredCustomers$ = this.customerControl.valueChanges.pipe(
      startWith(''),
      map(value => this.filterCustomers(value))
    );
  }

  originLabel(origin: string): string {
    const map: any = {
      factory_request: 'We request from factory',
      factory_offer: 'Factory offers to us',
      usa_bought: 'Bought in USA (send out)',
      customer: 'Customer (send from Ningbo)'
    };
    return map[origin] || origin;
  }

  onOriginChange(): void {
    if (this.model.origin !== 'customer') {
      this.model.customer_id_fk = null;
      this.customerControl.setValue(null, { emitEvent: false });
      return;
    }
    this.model.office_location = 'Ningbo';
    this.model.next_stop = 'Customer';
    this.model.final_destination = 'Customer';
  }

  displayCustomer(value: CustomerOption | string | null): string {
    if (!value) return '';
    if (typeof value === 'string') return value;
    return value.customers_name || '';
  }

  onCustomerSelected(customer: CustomerOption): void {
    this.model.customer_id_fk = customer ? customer.customers_id : null;
  }

  private filterCustomers(value: CustomerOption | string | null): CustomerOption[] {
    const query = this.displayCustomer(value).trim().toLowerCase();
    if (!query) return this.customers.slice(0, 50);
    return this.customers
      .filter(c => (c.customers_name || '').toLowerCase().includes(query))
      .slice(0, 50);
  }

  get previewStatus(): string {
    const def = ORIGIN_DEFAULTS[this.model.origin];
    return def ? `${statusLabel(def.initialStatus)} (${directionLabel(def.direction)})` : '';
  }

  get canSave(): boolean {
    const hasRoute = !!this.model.origin && !!this.model.next_stop && !!this.model.final_destination;
    if (this.model.origin === 'customer') return hasRoute && !!this.model.customer_id_fk;
    return hasRoute;
  }

  save(): void {
    if (!this.canSave) return;
    this.dialogRef.close({ ...this.model });
  }

  cancel(): void { this.dialogRef.close(); }
}

