.create-dialog {
  // Use the room a desktop dialog has instead of a single squished column.
  // The grid lays paired fields side by side so the form is short enough to fit
  // without an inner scrollbar.
  .grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4px 16px;
    align-items: start;
  }

  // Fields that should span both columns.
  .full { grid-column: 1 / -1; }

  mat-form-field { width: 100%; }

  .preview {
    margin: 0 0 8px;
    color: #1565c0;
    font-size: 13px;
  }

  .photo {
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding: 8px 0 4px;

    .photo-label {
      font-size: 12px;
      color: rgba(0, 0, 0, 0.6);
    }

    .photo-body {
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .photo-thumb {
      width: 72px;
      height: 72px;
      object-fit: cover;
      border-radius: 6px;
      border: 1px solid rgba(0, 0, 0, 0.12);
    }

    .photo-actions {
      display: flex;
      align-items: center;
      gap: 8px;
      flex-wrap: wrap;
    }

    .photo-name {
      font-size: 12px;
      color: rgba(0, 0, 0, 0.6);
      max-width: 260px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    .photo-error {
      margin: 0;
      color: #c62828;
      font-size: 12px;
    }
  }
}

// Narrow screens: collapse to a single column so it still works on small viewports.
@media (max-width: 599px) {
  .create-dialog .grid { grid-template-columns: 1fr; }
}

