async onNewSample(): Promise<void> {
  if (!this.customers.length) await this.loadCustomers();
  const ref = this.dialog.open(CreateDialogComponent, { width: '560px', data: { customers: this.customers } });
  const result = await firstValueFrom(ref.afterClosed());
  if (!result) return;
  try {
    await firstValueFrom(this.trackingService.createSample(result));
    this.toast('Sample created');
    await this.loadSamples();
  } catch (e: any) {
    this.toast(this.errMsg(e, 'Failed to create sample'));
  }
}

input.new_string:
async onNewSample(): Promise<void> {
  if (!this.customers.length) await this.loadCustomers();
  const ref = this.dialog.open(CreateDialogComponent, { width: '760px', maxWidth: '95vw', data: { customers: this.customers } });
  const result = await firstValueFrom(ref.afterClosed());
  if (!result) return;
  // __photoFile is carried by the dialog only; strip it before persisting.
  const photoFile: File | null = result.__photoFile || null;
  delete result.__photoFile;
  try {
    const created: any = await firstValueFrom(this.trackingService.createSample(result));
    if (photoFile && created && created.sample_id_pk != null) {
      try {
        await this.uploadSamplePhoto(created.sample_id_pk, photoFile, true);
      } catch {
        this.toast('Sample created, but photo upload failed');
        await this.loadSamples();
        return;
      }
    }
    this.toast('Sample created');
    await this.loadSamples();
  } catch (e: any) {
    this.toast(this.errMsg(e, 'Failed to create sample'));
  }
}

// Presigned upload flow (mirrors detail-dialog): presign -> PUT to storage ->
// make public -> register the attachment against the sample.
private async uploadSamplePhoto(sampleId: number, file: File, primary: boolean): Promise<void> {
  const safe = file.name.toLowerCase().replace(/[^a-z0-9.\-]+/g, '-');
  const fileName = `samples/sample-${sampleId}-${new Date().getTime()}-${safe}`;
  const contentType = file.type || 'image/jpeg';
  const presign: any = await firstValueFrom(this.trackingService.getSamplePreSignedUrl({ fileName, contentType }));
  const putRes = await fetch(presign.url, { method: 'PUT', body: file, headers: { 'Content-Type': contentType } });
  if (!putRes.ok) throw new Error('upload failed');
  const pub: any = await firstValueFrom(this.trackingService.setSampleObjectPublic({ fileName }));
  await firstValueFrom(this.trackingService.addSamplePhoto({
    sample_id_fk: sampleId,
    attachment_link: pub.publicUrl,
    sample_attachment_fileName: fileName,
    attachment_type: contentType,
    primary_image: primary
  }));
}

