import { describe, expect, it, jest, beforeEach } from '@jest/globals';
import { CreateDialogComponent } from './create-dialog.component';

// The dialog form logic is plain class behaviour, so we exercise it by
// instantiating the component with a mock MatDialogRef (no TestBed needed).
function makeComponent(customers: any[] = []) {
  const dialogRef = { close: jest.fn() } as any;
  const data = { customers };
  const comp = new CreateDialogComponent(dialogRef, data);
  return { comp, dialogRef };
}

describe('CreateDialogComponent', () => {
  describe('canSave', () => {
    it('requires a final destination (next stop is NOT required)', () => {
      const { comp } = makeComponent();
      comp.model.origin = 'factory_request';
      comp.model.final_destination = null;
      comp.model.next_stop = 'Ningbo';
      expect(comp.canSave).toBe(false); // no final destination

      comp.model.final_destination = 'NYC';
      comp.model.next_stop = null;       // next stop blank is allowed
      expect(comp.canSave).toBe(true);
    });

    it('also requires a customer for customer-origin samples', () => {
      const { comp } = makeComponent();
      comp.model.origin = 'customer';
      comp.model.final_destination = 'Customer';
      comp.model.customer_id_fk = null;
      expect(comp.canSave).toBe(false);

      comp.model.customer_id_fk = 42;
      expect(comp.canSave).toBe(true);
    });
  });

  describe('save', () => {
    it('defaults next stop to the final destination when left blank', () => {
      const { comp, dialogRef } = makeComponent();
      comp.model.origin = 'usa_bought';
      comp.model.final_destination = 'Factory';
      comp.model.next_stop = null;

      comp.save();

      expect(dialogRef.close).toHaveBeenCalledTimes(1);
      const payload: any = (dialogRef.close as any).mock.calls[0][0];
      expect(payload.next_stop).toBe('Factory');         // defaulted to final destination
      expect(payload.final_destination).toBe('Factory');
      expect(payload.__photoFile).toBeNull();
    });

    it('keeps an explicit next stop when one is chosen', () => {
      const { comp, dialogRef } = makeComponent();
      comp.model.origin = 'usa_bought';
      comp.model.final_destination = 'Factory';
      comp.model.next_stop = 'Ningbo';

      comp.save();

      const payload: any = (dialogRef.close as any).mock.calls[0][0];
      expect(payload.next_stop).toBe('Ningbo');
    });

    it('passes the selected photo file to the parent via __photoFile', () => {
      const { comp, dialogRef } = makeComponent();
      comp.model.origin = 'factory_request';
      comp.model.final_destination = 'NYC';
      const file = new File(['x'], 'pic.png', { type: 'image/png' });
      comp.photoFile = file;

      comp.save();

      const payload: any = (dialogRef.close as any).mock.calls[0][0];
      expect(payload.__photoFile).toBe(file);
    });

    it('does nothing when the form is not yet valid', () => {
      const { comp, dialogRef } = makeComponent();
      comp.model.origin = 'factory_request';
      comp.model.final_destination = null;
      comp.save();
      expect(dialogRef.close).not.toHaveBeenCalled();
    });
  });

  describe('photo selection', () => {
    it('accepts an image file', () => {
      const { comp } = makeComponent();
      const file = new File(['x'], 'pic.png', { type: 'image/png' });
      comp.onPhotoSelected({ target: { files: [file], value: '' } } as any);
      expect(comp.photoFile).toBe(file);
      expect(comp.photoError).toBeNull();
    });

    it('rejects a non-image file', () => {
      const { comp } = makeComponent();
      const file = new File(['x'], 'doc.pdf', { type: 'application/pdf' });
      comp.onPhotoSelected({ target: { files: [file], value: '' } } as any);
      expect(comp.photoFile).toBeNull();
      expect(comp.photoError).toBeTruthy();
    });

    it('removePhoto clears the selection', () => {
      const { comp } = makeComponent();
      comp.photoFile = new File(['x'], 'pic.png', { type: 'image/png' });
      comp.photoPreview = 'data:...';
      comp.removePhoto();
      expect(comp.photoFile).toBeNull();
      expect(comp.photoPreview).toBeNull();
    });
  });

  describe('onOriginChange', () => {
    it('prefills the customer route when origin becomes customer', () => {
      const { comp } = makeComponent();
      comp.model.origin = 'customer';
      comp.onOriginChange();
      expect(comp.model.office_location).toBe('Ningbo');
      expect(comp.model.next_stop).toBe('Customer');
      expect(comp.model.final_destination).toBe('Customer');
    });
  });
});

