private afterMetadataReady(): void {
  this.verifyVendorMode();
  // NOTE: getLicenseList()/getCBM() are no longer called here — they are loaded in
  // parallel up front by loadInitialMetadata() and applied (licenseRateMap,
  // cbmOptions) before this runs. See the forkJoin note above.
  this.getAllRFQItem();
}

// loadRFQStatuses() and loadRFQSteps() were merged into loadInitialMetadata()'s
// forkJoin (2026-06-22). The processing logic lives in prepareDivisionStatus()
// and applyRFQSteps() respectively.
private applyRFQSteps(data: any[]): void {
  // Store step list for clipboard operations (separate from status)
  this.stepList = data || [];
  // Pre-populate autocomplete cache so the first Step cell click is instant.
  if (data?.length && !window['rfq-autocomplete']?.step?.options) {
    if (!window['rfq-autocomplete']) window['rfq-autocomplete'] = {};
    window['rfq-autocomplete'].step = {
      options: data.map((d: any) => ({ title: d.RFQStep_title, id: d.RFQStep_id }))
    };
  }
}

private prepareDivisionStatus(res: any[]): void {
  this.selectedDivisionCodeStatus = [];

  if (this.role !== 'vendor') {
    this.selectedDivisionCodeStatus.push(res[0]);
    if (this.role === 'designer') {
      this.selectedDivisionCodeStatus.push(res[2]);
    }
  } else {
    this.selectedDivisionCodeStatus = res;
  }

  this.divisionCodeStatus = [...res];
  window['selectedDivisionCodeStatus'] = this.selectedDivisionCodeStatus;
}

