// Common mixin for page component layouts
@mixin page-component-layout {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.grid-wrapper, .mat-toolbar {
  box-shadow: 0 -5px 15px rgba(0, 0, 0, 0.2), -5px 0 15px rgba(0, 0, 0, 0.15), 5px 0 15px rgba(0, 0, 0, 0.15);
  border-radius: 7px;
}

.mdc-notched-outline__notch  {
  border-right:none !important;
}

.mat-mdc-option .mdc-list-item__primary-text {
  width: 100% !important;
}

.item-detail-input-section {
  width: 14.2em;
  font-size: 12px;
  word-break: break-all;
}

.firstTab_item-detail-input-section {
  width: 25rem;
  font-size: 12px;
  word-break: break-all;
}

.item-detail-section {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  font-size: 12px;
  white-space: nowrap;
  gap: 10px;
  padding-left: 1rem;
}
@media only screen and (min-width: 950px) {
  .item-detail-div-divider-firstTap {
    width: 50%;
    margin-top: 6%;
  }
  .item-detail-div-divider {
    width: 35%;
  }
  .item-detail-div {
    display: flex;
  }
  .item-detail-card {
    display: flex;
    flex-direction: row;
  }
  .image-viewer {
    width: 85%;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    margin-right: 1%;
  }
  .tracking {
    display: flex;
    justify-content: space-around;
    align-items: center;
  }
  .image-mat {
    max-width: 100% !important;
  }
  .item-detail-div-split {
    width: unset;
  }
}

@media only screen and (max-width: 950px) {
  .item-detail-div-divider-firstTap {
    width: unset;
    align-self: center;
  }
  .item-detail-div-divider {
    width: unset;
    align-self: center;
  }
  .item-detail-div {
    display: flex;
    flex-direction: column;
    overflow: auto;
    align-items: flex-end;
  }
  .item-detail-top-div {
    margin-top: 15%;
  }
  .item-detail-card {
    display: unset;
  }
  .image-viewer {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }
  .tracking {
    word-break: break-word;
    display: flex;
    flex-direction: column;
  }
  .image-mat {
    max-width: 100% !important;
    margin-bottom: 2%;
  }
  .item-detail-div-split {
    width: min-content;
  }
}

.item-detail-img-card {
  margin-right: 1%;
}

.chat-div-account_circle {
  display: flex;
}
.second-account_circle {
  color: black;
  margin-top: -1em;
  margin-left: -1em;
  z-index: 1;
}
.first-account_circle {
  color: black;
  margin-top: -1em;
  margin-right: -1em;
  z-index: 1;
}

.chat {
  display: flex;
  flex-direction: column;
  padding: 10px;
}

.messages {
  margin-top: 30px;
  display: flex;
  flex-direction: column;
}

.message {
  border-radius: 20px;
  padding: 8px 15px;
  margin-top: 5px;
  margin-bottom: 5px;
  display: inline-block;
}

.second {
  align-items: flex-start;
}

.second .message {
  max-width: calc(100% - 50%);
  word-wrap: break-word;
  margin-left: 0.5em;
  background-color: #eee;
  position: relative;
}

.second .message.last:before {
  content: "";
  position: absolute;
  z-index: 0;
  bottom: 0;
  left: -7px;
  height: 21px;
  width: 20px;
  background: #eee;
  border-bottom-right-radius: 15px;
}
.second .message.last:after {
  content: "";
  position: absolute;
  z-index: 1;
  bottom: 0;
  left: -10px;
  width: 10px;
  height: 21px;
  background: white;
  border-bottom-right-radius: 10px;
}

.first {
  align-items: flex-end;
}

.first .message {
  max-width: calc(100% - 50%);
  word-wrap: break-word;
  color: white;
  margin-right: 0.5em;
  background: linear-gradient(to bottom, #00d0ea 0%, #0085d1 100%);
  background-attachment: fixed;
  position: relative;
}

.first .message.last:before {
  content: "";
  position: absolute;
  z-index: 0;
  bottom: 0;
  right: -8px;
  height: 21px;
  width: 20px;
  background: linear-gradient(to bottom, #00d0ea 0%, #0085d1 100%);
  background-attachment: fixed;
  border-bottom-left-radius: 15px;
}

.first .message.last:after {
  content: "";
  position: absolute;
  z-index: 1;
  bottom: 0;
  right: -10px;
  width: 10px;
  height: 21px;
  background: white;
  border-bottom-left-radius: 10px;
}

tr.element-row:not(.expanded-row):hover {
  background: whitesmoke;
}

tr.element-row:not(.expanded-row):active {
