const content = document.querySelector('.create-dialog') || document.querySelector('.mat-mdc-dialog-content');
const csContent = getComputedStyle(content);
const contentRect = content.getBoundingClientRect();

const fields = [...document.querySelectorAll('.create-dialog mat-form-field')].map(ff => {
  const label = ff.querySelector('.mat-mdc-floating-label, label');
  const r = ff.getBoundingClientRect();
  const lr = label ? label.getBoundingClientRect() : null;
  return {
    label: label ? label.textContent.trim() : '?',
    width: Math.round(r.width),
