toolUseResult.originalFile:
.create-dialog {
  // A little top padding so the first outlined field's floating label is not
  // clipped by the dialog content's top edge.
  padding-top: 6px;

  .grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    column-gap: 16px;
    row-gap: 8px;
    align-items: start;
  }

  // Fields that should span both columns.
  .full { grid-column: 1 / -1; }

  mat-form-field { width: 100%; }

  .preview {
    margin: 2px 0;
    color: #1565c0;
    font-size: 13px;
  }

  .photo {
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding-top: 2px;

    .photo-body {
      display: flex;
      align-items: center;
      gap: 10px;
      flex-wrap: wrap;
    }

    .photo-thumb {
      width: 56px;
      height: 56px;
      object-fit: cover;
      border-radius: 6px;
      border: 1px solid rgba(0, 0, 0, 0.12);
    }

    .photo-name {
      font-size: 12px;
      color: rgba(0, 0, 0, 0.6);
      max-width: 240px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    .photo-error {
      margin: 0;
      color: #c62828;
      font-size: 12px;
    }
  }
}

// Narrow screens: collapse to a single column so it still works on small viewports.
@media (max-width: 599px) {
  .create-dialog .grid { grid-template-columns: 1fr; }
}

