toolUseResult.originalFile:
.create-dialog {
  // Flex-wrap so each field takes only the width it needs (sized to its label /
  // content) instead of a rigid half-and-half grid. Short numeric/select fields
  // pack onto shared rows; text fields span the full width.
  .form {
    display: flex;
    flex-wrap: wrap;
    align-items: flex-start;
    gap: 10px 12px;
  }

  // Width buckets. Each is wide enough for its floating label; numbers/selects
  // are kept tight, text fields grow to fill the row.
  .w-full   { flex: 1 1 100%; }
  .w-grow   { flex: 1 1 200px; }   // tracking number — fills the rest of its row
  .w-qty    { flex: 0 0 96px; }
  .w-num    { flex: 0 0 120px; }   // factory id / retail / fob
  .w-courier{ flex: 0 0 140px; }
  .w-office { flex: 1 1 200px; }
  .w-stop   { flex: 0 0 168px; }   // next stop / final destination

  mat-form-field { width: 100%; }

  .preview {
    margin: 2px 0;
    color: #1565c0;
    font-size: 13px;
  }

  .photo {
    display: flex;
    flex-direction: column;
    gap: 6px;

    .photo-body {
      display: flex;
      align-items: center;
      gap: 10px;
      flex-wrap: wrap;
    }

    .photo-thumb {
      width: 56px;
      height: 56px;
      object-fit: cover;
      border-radius: 6px;
      border: 1px solid rgba(0, 0, 0, 0.12);
    }

    .photo-name {
      font-size: 12px;
      color: rgba(0, 0, 0, 0.6);
      max-width: 240px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    .photo-error {
      margin: 0;
      color: #c62828;
      font-size: 12px;
    }
  }
}

// Narrow screens: stack everything in one column.
@media (max-width: 599px) {
  .create-dialog .form > * { flex: 1 1 100% !important; }
}

